#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(std::vector<long long> nums) {
    long long max_product = 0;
    int n = nums.size();

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if ((nums[i] & nums[j]) == 0) {
                long long current = nums[i] * nums[j];
                if (current > max_product) {
                    max_product = current;
                }
            }
        }
    }

    return max_product;
}
